/**
 * MMS Drift Monitor Service
 *
 * Monitors plan stability by comparing actual fleet state against published baselines.
 * Runs nightly drift analysis and generates alerts when thresholds are exceeded.
 *
 * Key responsibilities:
 * - Compare current mileage against baseline projections
 * - Compare current PM schedule against baseline snapshots
 * - Generate alerts when drift exceeds thresholds
 * - Persist drift analysis results for trending
 * - Update Prometheus metrics for monitoring
 *
 * Drift Thresholds (from spec):
 * - Mileage: ±5.0%
 * - Schedule: ±14 days
 * - Fleet: ≥5 trains requiring replan triggers CRITICAL alert
 *
 * @see specs/004-domain-services.md Section 4.10
 */

import { eq, and, desc, sql, inArray, gte, lte, isNull, count } from 'drizzle-orm';
import { differenceInDays, format, parseISO } from 'date-fns';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  driftAnalysis,
  planBaselines,
  baselineMileageProjection,
  baselinePmSchedule,
  pmSchedule,
  trains,
  pmTypes,
  type PlanBaseline,
  type DriftAnalysis,
} from '../lib/db/schema';
import { NotFoundError } from '../lib/errors';
import {
  driftTrainsRequiringReplan,
  driftMileagePercent,
  driftAnalysisTotal,
} from '../lib/metrics';

// =============================================================================
// Types
// =============================================================================

/** Drift threshold configuration */
export interface DriftThresholds {
  /** Maximum acceptable mileage drift percentage (default: 5.0) */
  mileageDriftPct: number;
  /** Maximum acceptable PM schedule drift in days (default: 14) */
  scheduleDriftDays: number;
  /** Fleet-level threshold for CRITICAL alert (default: 5) */
  fleetDriftTrainCount: number;
}

/** Default thresholds from specification */
export const DEFAULT_DRIFT_THRESHOLDS: DriftThresholds = {
  mileageDriftPct: 5.0,
  scheduleDriftDays: 14,
  fleetDriftTrainCount: 5,
};

/** Direction of PM schedule drift */
export type DriftDirection = 'LATER' | 'EARLIER' | 'ON_TRACK';

/** Drift analysis for individual PM */
export interface PMDrift {
  pmTypeId: string;
  pmCode: string;
  baselineDate: string;
  currentDate: string;
  driftDays: number;
  direction: DriftDirection;
}

/** Per-train drift analysis result */
export interface TrainDriftAnalysis {
  trainId: string;
  trainNumber: string;

/**
 * MMS Simulation Service (Simulation Engine)
 *
 * Enables what-if scenario analysis with persistent storage and comparison capabilities.
 * Uses event-sourcing pattern for tracking changes through deltas.
 *
 * Key responsibilities:
 * - Create scenarios forked from baselines or other scenarios
 * - Apply changes (PM_MOVE, PM_ADD, PM_REMOVE) as deltas
 * - Materialize scenarios by recursively applying deltas
 * - Compare scenarios side-by-side
 * - Promote winning scenarios to new baselines
 *
 * Scenario lifecycle:
 * ACTIVE -> (changes) -> PROMOTED or EXPIRED
 *
 * Auto-expiration: Scenarios expire after 30 days of inactivity.
 *
 * @see specs/004-domain-services.md Section 4.9
 */

import { eq, and, desc, asc, sql, inArray, lte, isNull, count, or } from 'drizzle-orm';
import { addDays, format, parseISO, differenceInDays } from 'date-fns';
import { BaseService } from '../lib/services/base';
import {
  scenarios,
  scenarioDeltas,
  scenarioComparisons,
  planBaselines,
  baselinePmSchedule,
  pmSchedule,
  auditLog,
  type Scenario,
  type ScenarioDelta,
  type PlanBaseline,
} from '../lib/db/schema';
import {
  NotFoundError,
  ValidationError,
  BusinessRuleError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Status of a scenario in its lifecycle */
export type ScenarioStatus = 'ACTIVE' | 'PROMOTED' | 'DISCARDED' | 'EXPIRED';

/** Delta types for scenario changes */
export type DeltaType =
  | 'PM_MOVE'
  | 'PM_ADD'
  | 'PM_REMOVE'
  | 'CAPACITY_CHANGE'
  | 'TRAIN_STATUS_CHANGE';

/** Entity types that can be modified in scenarios */
export type EntityType = 'pm_schedule' | 'manhour_capacity' | 'train';

/** Fork source specification */
export interface ForkSource {
  type: 'BASELINE' | 'SCENARIO' | 'PRODUCTION';
  id?: string; // Required for BASELINE and SCENARIO, not for PRODUCTION
}

/** Request to create a new scenario */
export interface CreateScenarioRequest {
  name: string;
  description?: string;
  forkFrom: ForkSource;
  userId: string;
  expirationDays?: number; // Default: 30
}

/** Change to apply to a scenario */
export interface ScenarioChange {
  type: DeltaType;
  entityType: EntityType;
  entityId: string;

