/**
 * MMS Route Utilization Service
 *
 * Provides route-specific daily mileage rates for accurate long-term projections.
 * Critical for PM scheduling as fleet-wide averages can result in 60,000+ km
 * projection error over the 12-year contract period.
 *
 * Key responsibilities:
 * - Retrieve route-specific utilization profiles
 * - Calculate expected daily km for trains with fallback hierarchy
 * - Project cumulative mileage over time horizons
 * - Apply seasonal multipliers for peak/off-peak periods
 *
 * Fallback hierarchy (in priority order):
 * 1. Route-specific profile from route_utilization_profiles table
 * 2. Fleet-wide average from last 30 days of mileage readings
 * 3. System default: 250 km/day (conservative estimate)
 *
 * @see specs/004-domain-services.md Section 4.2.7 (Route Utilization Service)
 * @see specs/003-database-schema.md Section 3.2.2 (Route Utilization Profiles)
 */

import { eq, and, sql, desc, lte, gte, avg, inArray } from 'drizzle-orm';
import type { SQL } from 'drizzle-orm';
import { addDays } from 'date-fns';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  routeUtilizationProfiles,
  trains,
  fleets,
  routes,
  mileageReadings,
  runAssignments,
  type RouteUtilizationProfile,
  type NewRouteUtilizationProfile,
} from '../lib/db/schema';
import { NotFoundError, ValidationError, DuplicateError } from '../lib/errors';
import { addJob, QUEUE_NAMES } from '../lib/queue';

// =============================================================================
// Types
// =============================================================================

/** Day type for utilization lookup */
export type UtilizationDayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';

/** Confidence level for mileage estimates */
export type ConfidenceLevel = 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';

/** Source of the daily rate calculation */
export type RateSource =
  | `route:${string}` // Route-specific profile with route ID
  | 'fleet_average'   // Calculated from recent mileage readings
  | 'system_default'; // Conservative fallback (250 km/day)

/** Result of daily rate calculation */
export interface DailyRateResult {
  dailyKm: number;
  source: RateSource;
  confidence: ConfidenceLevel;
  details?: {
    routeId?: string;
    routeCode?: string;
    fleetId?: string;
    fleetCode?: string;
    dayType?: UtilizationDayType;
    seasonalMultiplier?: number;
    profileEffectiveDate?: string;
  };
}

/** Single day projection */
export interface MileageProjection {
  date: string;
  projectedDailyKm: number;
  cumulativeKm: number;
  source: RateSource;
  confidence: ConfidenceLevel;
}

