## 4.3 Run Assignment Optimizer

### 4.3.1 Purpose

Optimize daily train-to-route assignments for mileage balancing while respecting hard constraints (fitness, PM due, **unavailability**, **service demand**) and minimizing soft constraint penalties.

### 4.3.2 Optimizer Service (TypeScript Wrapper)

```typescript
interface OptimizerConfig {
  binaryPath: string;          // ./mms-optimizer
  maxSolveTimeSeconds: number; // 30
  numWorkers: number;          // 4
  timeoutMs: number;           // 60000
  fallbackEnabled: boolean;    // true
}

class RunAssignmentOptimizer {
  private process: Subprocess | null = null;

  async optimize(input: OptimizerInput): Promise<OptimizerResult> {
    const startTime = Date.now();

    try {
      // Try C++ optimizer first
      const result = await this.runCppOptimizer(input);

      // Validate result
      if (result.status === 'INFEASIBLE' && this.config.fallbackEnabled) {
        this.logger.warn('C++ optimizer returned INFEASIBLE, using fallback');
        return await this.runFallbackOptimizer(input);
      }

      return result;

    } catch (error) {
      this.logger.error({ error }, 'C++ optimizer failed, using fallback');

      if (this.config.fallbackEnabled) {
        return await this.runFallbackOptimizer(input);
      }

      throw error;
    }
  }

  private async runCppOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
    return new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        this.process?.kill();
        reject(new Error('Optimizer timeout'));
      }, this.config.timeoutMs);

      this.process = Bun.spawn([this.config.binaryPath], {
        stdin: 'pipe',
        stdout: 'pipe',
        stderr: 'pipe'
      });

      // Write input
      const writer = this.process.stdin.getWriter();
      writer.write(new TextEncoder().encode(JSON.stringify(input) + '\n'));
      writer.close();

      // Read stdout (results)
      const results: any[] = [];
      const reader = this.process.stdout.getReader();
      const decoder = new TextDecoder();
      let buffer = '';

      const readStream = async () => {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          buffer = lines.pop() || '';

          for (const line of lines) {
            if (!line.trim()) continue;

            try {
              const msg = JSON.parse(line);

              if (msg.type === 'PROGRESS') {
                this.emitProgress(msg);
              } else if (msg.type === 'RESULT') {
                clearTimeout(timeout);
                resolve(this.mapResult(msg));
                return;
              }
            } catch (e) {
              this.logger.warn({ line }, 'Failed to parse optimizer output');
            }
          }
        }
      };

      // Read stderr (metrics/logs)

