/**
 * MMS Optimizer Worker Processor
 *
 * BullMQ job processor for run assignment optimization.
 * Handles job lifecycle, progress reporting, and result storage.
 *
 * Job Flow:
 * 1. Receive OptimizerJobData from queue
 * 2. Fetch trains, routes, constraints from database
 * 3. Build OptimizerFullInput
 * 4. Run optimizer (C++ or fallback)
 * 5. Store results and broadcast via WebSocket
 *
 * @see specs/002-architecture.md Section 2.2.4
 * @see specs/004-domain-services.md Section 4.3
 */

import { logger } from '../../lib/logging/logger';
import { withSpan } from '../../lib/tracing';
import { db } from '../../lib/db/connection';
import { ValidationError } from '../../lib/errors';
import { optimizerMetrics } from '../../lib/metrics';
import { type WorkerJobContext } from '../index';
import { type OptimizerJobData } from '../../lib/queue';
import {
  runAssignmentOptimizer,
  type OptimizerFullInput,
  type OptimizerFullResult,
  type OptimizerTrainInput,
  type OptimizerRouteInput,
  type HardConstraint,
  type SoftConstraint,
  type UnavailabilityEvent,
  type ServiceDemand,
  DEFAULT_OPTIMIZER_CONFIG,
} from '../../optimizer';

// Import database schemas
import { trains, fleets, unavailabilityEvents, serviceDemand, runAssignments } from '../../lib/db/schema';
import { eq, and, sql } from 'drizzle-orm';

// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'optimizer' });

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process optimizer job
 *
 * Fetches required data, builds input, runs optimization,
 * and stores/broadcasts results.
 */
export async function processOptimizerJob(
  context: WorkerJobContext<OptimizerJobData>
): Promise<OptimizerFullResult> {
  return withSpan('worker.optimizer.process', async (span) => {
    const { id, data } = context;
    const { date, fleetId, constraints, timeoutMs } = data;

    span.setAttribute('jobId', id);
    span.setAttribute('date', date);
    span.setAttribute('fleetId', fleetId);
    span.setAttribute('hasConstraints', !!constraints);

    log.info({ jobId: id, date, fleetId }, 'Processing optimizer job');

    // Update progress: fetching data
    await context.updateProgress({ stage: 'FETCHING_DATA', percent: 10 });
    await context.log('Fetching trains and routes from database');

    // Build optimizer input
    const input = await buildOptimizerInput(date, fleetId, constraints, timeoutMs);

    // Update progress: optimizing
    await context.updateProgress({ stage: 'OPTIMIZING', percent: 30 });

